---
// Generated from bejamas-juno style registry. Do not edit packages/ui/src/components/button-group/ButtonGroupSeparator.astro directly.
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";
import Separator from "../separator/Separator.astro";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
  orientation?: "horizontal" | "vertical";
  decorative?: boolean;
}

const {
  class: className = "",
  orientation = "vertical",
  decorative = true,
  ...rest
} = Astro.props as Props;
---

<Separator
  {...rest}
  decorative={decorative}
  data-slot="button-group-separator"
  data-orientation={orientation}
  orientation={orientation}
  class={cn(
    "bg-input relative self-stretch data-[orientation=horizontal]:mx-px data-[orientation=horizontal]:w-auto data-[orientation=vertical]:my-px data-[orientation=vertical]:h-auto",
    className,
  )}
/>

---
// Generated from bejamas-juno style registry. Do not edit packages/ui/src/components/button-group/ButtonGroupText.astro directly.
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
}

const { class: className = "", ...rest } = Astro.props as Props;
---

<div
  {...rest}
  data-slot="button-group-text"
  class={cn(
    "bg-muted gap-2 rounded-md border px-2.5 text-sm font-medium shadow-xs [&_svg:not([class*='size-'])]:size-4",
    "bg-muted flex items-center gap-2 rounded-lg border px-2.5 text-sm font-medium [&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none",
    className,
  )}
>
  <slot />
</div>

